// Domain events for a BankAccount aggregate. Past-tense facts, immutable.
interface DomainEvent { readonly type: string; }
interface AccountOpened extends DomainEvent { type: 'AccountOpened'; accountId: string; owner: string; }
interface FundsDeposited extends DomainEvent { type: 'FundsDeposited'; amount: number; }
interface FundsWithdrawn extends DomainEvent { type: 'FundsWithdrawn'; amount: number; }
type AccountEvent = AccountOpened | FundsDeposited | FundsWithdrawn;

class BankAccount {
  private id = '';
  private balance = 0;
  private opened = false;
  private changes: AccountEvent[] = []; // uncommitted events
  version = -1;                         // last persisted stream version

  // Rebuild from history: empty state folded over past events.
  static fromHistory(history: AccountEvent[]): BankAccount {
    const acc = new BankAccount();
    for (const e of history) { acc.apply(e); acc.version++; }
    return acc;
  }

  // Command handler: validate, then RAISE an event (do not mutate directly).
  withdraw(amount: number): void {
    if (!this.opened) throw new Error('Account not open');
    if (amount <= 0) throw new Error('Amount must be positive');
    if (amount > this.balance) throw new Error('Insufficient funds'); // overdraft rejected
    this.raise({ type: 'FundsWithdrawn', amount });
  }

  private raise(e: AccountEvent): void { this.apply(e); this.changes.push(e); }

  // apply/evolve: total, deterministic, NO validation, NO side effects.
  private apply(e: AccountEvent): void {
    switch (e.type) {
      case 'AccountOpened':  this.id = e.accountId; this.opened = true; break;
      case 'FundsDeposited': this.balance += e.amount; break;
      case 'FundsWithdrawn': this.balance -= e.amount; break;
    }
  }

  getUncommittedChanges(): AccountEvent[] { return this.changes; }
  markCommitted(): void { this.version += this.changes.length; this.changes = []; }
}

// Append with optimistic concurrency on the stream version.
public class JdbcEventStore {

  public void append(UUID streamId, long expectedVersion, List<EventRecord> newEvents) {
    try (Connection cx = dataSource.getConnection()) {
      cx.setAutoCommit(false);
      long version = expectedVersion; // version of the last event we loaded
      var ps = cx.prepareStatement(
        "INSERT INTO events(stream_id, version, event_type, payload, metadata) VALUES (?,?,?,?,?)");
      for (EventRecord e : newEvents) {
        version++; // next sequential slot
        ps.setObject(1, streamId);
        ps.setLong(2, version);
        ps.setString(3, e.type());
        ps.setString(4, e.payloadJson());
        ps.setString(5, e.metadataJson());
        ps.addBatch();
      }
      ps.executeBatch();
      cx.commit();
    } catch (SQLException dup) {
      // PK (stream_id, version) violation => someone else appended first.
      throw new ConcurrencyException(
        "Stream " + streamId + " was modified concurrently; reload and retry", dup);
    }
  }
}

// A projection handler that maintains a denormalized read model for an account list.
// The read model is a flat document optimized for a dashboard query.
interface AccountSummaryRow { accountId: string; owner: string; balance: number; lastActivity: string; }

class AccountSummaryProjection {
  constructor(private readonly db: ReadModelStore<AccountSummaryRow>) {}

  // Called once per event, in global commit order.
  async handle(streamId: string, event: AccountEvent, occurredAt: string): Promise<void> {
    switch (event.type) {
      case 'AccountOpened':
        await this.db.upsert({ accountId: streamId, owner: event.owner, balance: 0, lastActivity: occurredAt });
        break;
      case 'FundsDeposited': {
        const row = await this.db.get(streamId);
        await this.db.upsert({ ...row, balance: row.balance + event.amount, lastActivity: occurredAt });
        break;
      }
      case 'FundsWithdrawn': {
        const row = await this.db.get(streamId);
        await this.db.upsert({ ...row, balance: row.balance - event.amount, lastActivity: occurredAt });
        break;
      }
    }
  }
}

// Upcasting: transform legacy event shapes into the current shape at load time.
// v1 had a single 'name' field; v2 splits it into firstName/lastName.
type StoredEvent = { type: string; schemaVersion: number; data: any };

function upcastAccountOpened(e: StoredEvent): StoredEvent {
  if (e.type !== 'AccountOpened') return e;
  let data = e.data;
  let v = e.schemaVersion;
  if (v === 1) { // v1 -> v2: split owner name
    const [first, ...rest] = (data.owner ?? '').split(' ');
    data = { ...data, firstName: first, lastName: rest.join(' ') };
    delete data.owner;
    v = 2;
  }
  // future steps chain here: if (v === 2) { ...; v = 3; }
  return { ...e, schemaVersion: v, data };
}

-- Transactional outbox: events and outbox rows committed atomically.
BEGIN;
  INSERT INTO events (stream_id, version, event_type, payload, metadata)
  VALUES ('a1b2...', 8, 'FundsWithdrawn', '{"amount":50}', '{"eventId":"e-901"}');

  INSERT INTO outbox (id, aggregate_id, event_type, payload, status)
  VALUES ('e-901', 'a1b2...', 'FundsWithdrawn', '{"amount":50}', 'PENDING');
COMMIT;
-- A relay polls: SELECT * FROM outbox WHERE status='PENDING' ORDER BY id;
-- publish to broker, then UPDATE outbox SET status='SENT' WHERE id=...;
-- Consumers dedupe on id (eventId) so redelivery is harmless.

// Command handler tying the aggregate to the store with retry on conflict.
async function handleWithdraw(store: EventStore, cmd: { accountId: string; amount: number }) {
  for (let attempt = 0; attempt < 3; attempt++) {
    const history = await store.readStream(cmd.accountId);   // events (or snapshot + tail)
    const account = BankAccount.fromHistory(history);        // fold to current state
    account.withdraw(cmd.amount);                            // validate + raise event
    try {
      await store.append(cmd.accountId, account.version, account.getUncommittedChanges());
      account.markCommitted();
      return { ok: true, version: account.version };          // return result, avoid read-after-write
    } catch (e) {
      if (e instanceof ConcurrencyException) continue;        // reload and retry
      throw e;
    }
  }
  throw new Error('Too much contention on account ' + cmd.accountId);
}

