type DomainEvent =
  | { type: 'AccountOpened'; accountId: string; owner: string }
  | { type: 'FundsDeposited'; amount: number }
  | { type: 'FundsWithdrawn'; amount: number };

class BankAccount {
  private accountId = '';
  private owner = '';
  private balance = 0;
  private opened = false;
  private changes: DomainEvent[] = [];
  version = -1; // -1 means no events yet persisted

  // --- Reconstruction from history (pure fold) ---
  static fromHistory(history: DomainEvent[]): BankAccount {
    const acc = new BankAccount();
    for (const e of history) {
      acc.apply(e);
      acc.version++;
    }
    return acc;
  }

  // --- Command handlers: validate, then raise events ---
  static open(accountId: string, owner: string): BankAccount {
    if (!accountId) throw new Error('accountId required');
    if (!owner) throw new Error('owner required');
    const acc = new BankAccount();
    acc.raise({ type: 'AccountOpened', accountId, owner });
    return acc;
  }

  deposit(amount: number): void {
    if (!this.opened) throw new Error('Account not open');
    if (amount <= 0) throw new Error('Amount must be positive');
    this.raise({ type: 'FundsDeposited', amount });
  }

  withdraw(amount: number): void {
    if (!this.opened) throw new Error('Account not open');
    if (amount <= 0) throw new Error('Amount must be positive');
    if (amount > this.balance) throw new Error('Insufficient funds'); // overdraft rejected here
    this.raise({ type: 'FundsWithdrawn', amount });
  }

  // --- Event raising and applying ---
  private raise(e: DomainEvent): void {
    this.apply(e);
    this.changes.push(e);
  }

  // Pure, total, deterministic. No validation, no side effects.
  private apply(e: DomainEvent): void {
    switch (e.type) {
      case 'AccountOpened':
        this.accountId = e.accountId;
        this.owner = e.owner;
        this.opened = true;
        break;
      case 'FundsDeposited':
        this.balance += e.amount;
        break;
      case 'FundsWithdrawn':
        this.balance -= e.amount;
        break;
    }
  }

  // --- Persistence support ---
  getUncommittedChanges(): DomainEvent[] {
    return [...this.changes];
  }

  markChangesAsCommitted(): void {
    this.version += this.changes.length;
    this.changes = [];
  }

  getBalance(): number {
    return this.balance;
  }
}

// --- Example usage ---
const account = BankAccount.open('acc-1', 'Ada Lovelace');
account.deposit(100);
account.withdraw(30);
console.log(account.getBalance()); // 70
// Rebuild from history reproduces identical state:
const rebuilt = BankAccount.fromHistory(account.getUncommittedChanges());
console.log(rebuilt.getBalance()); // 70

interface AccountSummary {
  accountId: string;
  owner: string;
  balance: number;
  lastSeq: number; // highest global seq applied to this row
}

type AccountEvent =
  | { type: 'AccountOpened'; accountId: string; owner: string }
  | { type: 'FundsDeposited'; amount: number }
  | { type: 'FundsWithdrawn'; amount: number };

interface StoredEvent { seq: number; streamId: string; event: AccountEvent; }

// Simple in-memory read-model store (swap for a document DB in production).
class ReadModelStore {
  private rows = new Map<string, AccountSummary>();
  get(id: string): AccountSummary | undefined { return this.rows.get(id); }
  put(row: AccountSummary): void { this.rows.set(row.accountId, row); }
  all(): AccountSummary[] { return [...this.rows.values()]; }
  clear(): void { this.rows.clear(); }
}

class AccountSummaryProjection {
  constructor(private readonly store: ReadModelStore) {}

  // Idempotent: skip events already applied to this row.
  handle(seq: number, streamId: string, event: AccountEvent): void {
    const existing = this.store.get(streamId);
    if (existing && seq <= existing.lastSeq) {
      return; // duplicate / redelivery -> no-op
    }
    switch (event.type) {
      case 'AccountOpened':
        this.store.put({ accountId: streamId, owner: event.owner, balance: 0, lastSeq: seq });
        break;
      case 'FundsDeposited': {
        const row = this.require(existing, streamId);
        this.store.put({ ...row, balance: row.balance + event.amount, lastSeq: seq });
        break;
      }
      case 'FundsWithdrawn': {
        const row = this.require(existing, streamId);
        this.store.put({ ...row, balance: row.balance - event.amount, lastSeq: seq });
        break;
      }
    }
  }

  private require(row: AccountSummary | undefined, id: string): AccountSummary {
    if (!row) throw new Error('Event for unknown account ' + id + ' (stream out of order?)');
    return row;
  }

  // Rebuild from scratch: disposable read model replayed from the log.
  rebuild(allEvents: StoredEvent[]): void {
    this.store.clear();
    for (const e of allEvents.sort((a, b) => a.seq - b.seq)) {
      this.handle(e.seq, e.streamId, e.event);
    }
  }
}

// --- Example usage ---
const store = new ReadModelStore();
const projection = new AccountSummaryProjection(store);
const stream: StoredEvent[] = [
  { seq: 1, streamId: 'acc-1', event: { type: 'AccountOpened', accountId: 'acc-1', owner: 'Ada' } },
  { seq: 2, streamId: 'acc-1', event: { type: 'FundsDeposited', amount: 100 } },
  { seq: 3, streamId: 'acc-1', event: { type: 'FundsWithdrawn', amount: 30 } },
];
for (const e of stream) projection.handle(e.seq, e.streamId, e.event);
projection.handle(2, 'acc-1', { type: 'FundsDeposited', amount: 100 }); // redelivery: ignored
console.log(store.get('acc-1')); // { accountId:'acc-1', owner:'Ada', balance:70, lastSeq:3 }
projection.rebuild(stream);
console.log(store.get('acc-1')?.balance); // 70 (identical after rebuild)
